set phone = #{phone},
    modify_time = #{modifyTime}
where user_id = #{userId}
  and status >= 1

update `user`
set description = #{description},
    modify_time = #{modifyTime}
where user_id = #{userId}
  and status >= 1

update `user`
set nickname = #{nickname},
    modify_time = #{modifyTime}
where user_id = #{userId}
  and status >= 1
